contracts/Crowdfunding.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./RewardToken.sol";

contract Crowdfunding {
    struct Campaign {
        string title;
        uint256 goal;        // в wei
        uint256 deadline;    // timestamp
        uint256 totalRaised; // в wei
        bool finalized;
        address creator;
    }

    uint256 public campaignCount;
    RewardToken public rewardToken;

    mapping(uint256 => Campaign) public campaigns;
    mapping(uint256 => mapping(address => uint256)) public contributions;

    // 1 ETH -> 100 CRT (CRT имеет 18 decimals, как ETH wei)
    uint256 public constant REWARD_RATE = 100;

    constructor(address _rewardToken) {
        require(_rewardToken != address(0), "Zero reward token");
        rewardToken = RewardToken(_rewardToken);
    }

    // 1) Creation of campaigns
    function createCampaign(
        string calldata title,
        uint256 goalWei,
        uint256 durationSeconds
    ) external {
        require(bytes(title).length > 0, "Empty title");
        require(goalWei > 0, "Goal must be > 0");
        require(durationSeconds > 0, "Duration must be > 0");

        campaigns[campaignCount] = Campaign({
            title: title,
            goal: goalWei,
            deadline: block.timestamp + durationSeconds,
            totalRaised: 0,
            finalized: false,
            creator: msg.sender
        });

        campaignCount++;
    }

    // 2) Contribution of test ETH
    function contribute(uint256 campaignId) external payable {
        Campaign storage c = campaigns[campaignId];
        require(bytes(c.title).length > 0, "No such campaign");
        require(block.timestamp < c.deadline, "Campaign ended");
        require(msg.value > 0, "No ETH sent");

        c.totalRaised += msg.value;
        contributions[campaignId][msg.sender] += msg.value;

        // 5) Reward tokens proportional to contribution
        // msg.value is in wei; multiply by REWARD_RATE keeps decimals
        uint256 rewardAmount = msg.value * REWARD_RATE;
        rewardToken.mint(msg.sender, rewardAmount);
    }

    // 4) Finalization on deadline
    function finalizeCampaign(uint256 campaignId) external {
        Campaign storage c = campaigns[campaignId];
        require(bytes(c.title).length > 0, "No such campaign");
        require(block.timestamp >= c.deadline, "Not ended");
        require(!c.finalized, "Already finalized");

        c.finalized = true;

        // если собрали цель — отправляем создателю
        if (c.totalRaised >= c.goal) {
            (bool ok, ) = payable(c.creator).call{value: c.totalRaised}("");
            require(ok, "Transfer failed");
        }
    }

    function getCampaign(uint256 id) external view returns (Campaign memory) {
        return campaigns[id];
    }
}

contracts/RewardToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";

contract RewardToken is ERC20 {
    address public crowdfunding;

    constructor() ERC20("CrowdRewardToken", "CRT") {}

    function setCrowdfunding(address _cf) external {
        require(crowdfunding == address(0), "Already set");
        require(_cf != address(0), "Zero address");
        crowdfunding = _cf;
    }

    function mint(address to, uint256 amount) external {
        require(msg.sender == crowdfunding, "Only crowdfunding");
        _mint(to, amount);
    }
}

